import{_ as i,o as a,i as s,aB as t}from"./chunks/framework.CoTX8EIa.js";const k=JSON.parse('{"title":"其他 UI 组件库","description":"","frontmatter":{},"headers":[],"relativePath":"guide/other-ui.md","filePath":"guide/other-ui.md"}'),r={name:"guide/other-ui.md"};function l(d,e,n,p,o,h){return a(),s("div",null,[...e[0]||(e[0]=[t('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide/other-ui.md for this page in Markdown format</div><h1 id="其他-ui-组件库" tabindex="-1">其他 UI 组件库 <a class="header-anchor" href="#其他-ui-组件库" aria-label="Permalink to “其他 UI 组件库”">​</a></h1><h2 id="预设-ui-组件库" tabindex="-1">预设 UI 组件库 <a class="header-anchor" href="#预设-ui-组件库" aria-label="Permalink to “预设 UI 组件库”">​</a></h2><p>框架已为你集成好了以下 UI 组件库的工程，开箱即用，分别在 <code>apps/</code> 目录下的不同应用内：</p><ul><li><code>core-ant-design-vue</code> - <a href="https://www.antdv.com/" target="_blank" rel="noreferrer">Ant Design Vue</a></li><li><code>core-antdv-next</code> - <a href="https://www.antdv-next.com/" target="_blank" rel="noreferrer">Antdv Next</a></li><li><code>core-arco-design-vue</code> - <a href="https://arco.design/vue/" target="_blank" rel="noreferrer">Arco Design Vue</a></li><li><code>core-naive-ui</code> - <a href="https://www.naiveui.com/" target="_blank" rel="noreferrer">Naive UI</a></li><li><code>core-tdesign</code> - <a href="https://tdesign.tencent.com/vue-next/" target="_blank" rel="noreferrer">Tdesign</a></li><li><code>core-vexip-ui</code> - <a href="https://www.vexipui.com/" target="_blank" rel="noreferrer">Vexip UI</a></li></ul><h2 id="接入其他-ui-组件库" tabindex="-1">接入其他 UI 组件库 <a class="header-anchor" href="#接入其他-ui-组件库" aria-label="Permalink to “接入其他 UI 组件库”">​</a></h2><p>如果你需要使用的 UI 组件库不在其中，也可以参考以下步骤自行接入其他 UI 组件库。</p><h3 id="_1-复制-core-应用" tabindex="-1">1. 复制 <code>core</code> 应用 <a class="header-anchor" href="#_1-复制-core-应用" aria-label="Permalink to “1. 复制 core 应用”">​</a></h3><p>复制 <code>apps/core</code> 应用，同时修改 <code>apps/&lt;app&gt;/package.json</code> 中 <code>name</code> 属性。</p><h3 id="_2-修改-apps-app-src-ui-provider-目录" tabindex="-1">2. 修改 <code>apps/&lt;app&gt;/src/ui/provider</code> 目录 <a class="header-anchor" href="#_2-修改-apps-app-src-ui-provider-目录" aria-label="Permalink to “2. 修改 apps/&lt;app&gt;/src/ui/provider 目录”">​</a></h3><p>这个目录是框架对接 UI 组件库的统一入口，一共只有 2 个文件：</p><ul><li><code>index.ts</code>：负责安装 UI 组件库，如果是专业版，并且组件库支持国际化，还需要导出该组件库的语言包映射</li><li><code>index.vue</code>：负责在根组件外层包裹全局 Provider，并把框架的主题、语言等状态同步给 UI 组件库</li></ul><p>框架之所以能方便切换 UI 组件库，核心原因就在这里：</p><ul><li><code>main.ts</code> 中通过 <code>app.use(uiProvider)</code> 安装 UI 组件库</li><li><code>App.vue</code> 中通过 <code>&lt;Provider&gt;</code> 包裹整棵应用</li></ul><p>因此大多数情况下，你只需要改这两个文件，<code>main.ts</code> 和 <code>App.vue</code> 本身不需要动。</p><h3 id="_3-卸载-element-plus" tabindex="-1">3. 卸载 <code>element-plus</code> <a class="header-anchor" href="#_3-卸载-element-plus" aria-label="Permalink to “3. 卸载 element-plus”">​</a></h3><p>因为是从 <code>apps/core</code> 复制出来的，那么在完成新 UI 组件库的接入后，就可以把 <code>element-plus</code> 从当前应用中移除：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @fantastic-admin/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> element-plus</span></span></code></pre></div><p>除了卸载依赖，还建议再检查两处：</p><ul><li><code>apps/&lt;app&gt;/tsconfig.app.json</code> 中是否还保留了 <code>element-plus/global</code> 类型声明，如果有，需要删除或替换成目标 UI 组件库对应的类型声明</li><li>代码里是否还残留 <code>element-plus</code> 的样式或语言包引入</li></ul><p>可以通过下面的命令快速排查：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;element-plus|El[A-Z]&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apps/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div>',22)])])}const u=i(r,[["render",l]]);export{k as __pageData,u as default};
